Here's a modern MSTest test class for `DataFetcher`:

```csharp
[TestClass]
public sealed class DataFetcherTests
{
    private readonly TestContext _testContext;

    public DataFetcherTests(TestContext testContext)
    {
        _testContext = testContext;
    }

    private static HttpClient CreateClient(HttpStatusCode statusCode, string content = "")
    {
        var handler = new MockHandler(new HttpResponseMessage(statusCode)
        {
            Content = new StringContent(content),
        });
        return new HttpClient(handler);
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_SuccessResponse_ReturnsContent()
    {
        // Arrange
        var fetcher = new DataFetcher(CreateClient(HttpStatusCode.OK, "hello"));

        // Act
        var result = await fetcher.FetchAsync("https://example.com", _testContext.CancellationToken);

        // Assert
        Assert.AreEqual("hello", result);
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_NotFoundResponse_ThrowsHttpRequestException()
    {
        var fetcher = new DataFetcher(CreateClient(HttpStatusCode.NotFound));

        await Assert.ThrowsExactlyAsync<HttpRequestException>(
            async () => await fetcher.FetchAsync("https://example.com", _testContext.CancellationToken));
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_CancellationRequested_ThrowsOperationCanceledException()
    {
        using var cts = new CancellationTokenSource();
        var handler = new MockHandler(() =>
        {
            cts.Cancel();
            throw new OperationCanceledException(cts.Token);
        });
        var fetcher = new DataFetcher(new HttpClient(handler));

        await Assert.ThrowsAsync<OperationCanceledException>(
            async () => await fetcher.FetchAsync("https://example.com", cts.Token));
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_NullUrl_ThrowsException()
    {
        var fetcher = new DataFetcher(CreateClient(HttpStatusCode.OK));

        await Assert.ThrowsAsync<ArgumentNullException>(
            async () => await fetcher.FetchAsync(null!, _testContext.CancellationToken));
    }

    // Minimal test double for HttpMessageHandler
    private sealed class MockHandler : HttpMessageHandler
    {
        private readonly Func<HttpResponseMessage> _factory;

        public MockHandler(HttpResponseMessage response) => _factory = () => response;
        public MockHandler(Action callback) => _factory = () => { callback(); return null!; };

        protected override Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
        {
            cancellationToken.ThrowIfCancellationRequested();
            return Task.FromResult(_factory());
        }
    }
}
```

**Key patterns used:**

- **`sealed` test class** — best practice for performance
- **Constructor-injected `TestContext`** — enables `readonly` field
- **`[Timeout(5000)]` + `_testContext.CancellationToken`** — cooperative timeout; MSTest cancels the token when time expires
- **`Assert.ThrowsExactlyAsync<T>`** — exact type match for expected exceptions
- **`Assert.ThrowsAsync<T>`** — matches derived types (e.g., `TaskCanceledException` inherits `OperationCanceledException`)
- **`MockHandler`** — lightweight `HttpMessageHandler` stub avoids needing a mocking library

The cancellation test simulates a cancelled token mid-request, verifying `DataFetcher` properly propagates cancellation.
